# ============================================================
# lxd/Makefile ‚ÄĒ žĚłŪĒĄŽĚľ ž†Ąžö© (dorae222/hj žĄúŽ≤ĄžóźžĄúŽßĆ žč§ŪĖČ)
# žā¨žö©Ž≤ē: make -f lxd/Makefile <target>
# ============================================================

ROOT := $(realpath $(dir $(lastword $(MAKEFILE_LIST)))..)
REGISTRY ?= dorae222
TAG ?= latest

.PHONY: help push push-local deploy-test deploy-test-service rollback-stable \
        sync-dev-branches sync-lxd sync-all \
        check-lxd-git sync-dev-data health-lxd fix-lxd-jwt \
        dev-final-branches dev-final-checkout dev-final-rebuild dev-final-setup

help:
	@echo ""
	@echo "  [žĚłŪĒĄŽĚľ ž†Ąžö©] lxd/Makefile Ž™ÖŽ†ĻžĖī"
	@echo "  žč§ŪĖČ: make -f lxd/Makefile <target>"
	@echo ""
	@echo "  Docker Hub ŽįįŪŹ¨:"
	@echo "    push                   Ž™®Žď† žĚīŽĮłžßÄ Docker Hub push"
	@echo "    push-local             Ž°úžĽ¨ Ž†ąžßÄžä§ŪäłŽ¶¨(10.10.10.10:5000) push"
	@echo "    deploy-test            ŽĻĆŽďú ‚Üí push ‚Üí deploy-test ž†Ąž≤ī ŽįįŪŹ¨"
	@echo "    deploy-test-service    Žč®žĚľ žĄúŽĻĄžä§ ŽįįŪŹ¨ (SVC=frontend|backend-api|ai-pipeline)"
	@echo "    rollback-stable        feb20-stable žĚīŽĮłžßÄŽ°ú deploy-test Ž°§ŽįĪ"
	@echo "  ŽłĆŽěúžĻė/LXD žčĪŪĀ¨:"
	@echo "    sync-dev-branches      develop ‚Üí dev/* ŽłĆŽěúžĻė Ž≥ĎŪē© & push"
	@echo "    sync-lxd               ÍįĀ LXD žĄúŽ≤ĄžóźžĄú git pull žč§ŪĖČ"
	@echo "    sync-all               žúĄ ŽĎź žěĎžóÖ žąúžį® žč§ŪĖČ"
	@echo ""
	@echo "  LXD ÍįúŽįú ŪôėÍ≤Ĺ:"
	@echo "    check-lxd-git          ÍįĀ LXD žĄúŽ≤Ą git žĄ§ž†ē(user/email/remote/SSH) ž†źÍ≤Ä"
	@echo "    health-lxd             5ŽĆÄ žĄúŽ≤Ą git ŽłĆŽěúžĻė/Docker žĽ®ŪÖĆžĚīŽĄą žÉĀŪÉú ŪēúŽąąžóź Ž≥īÍłį"
	@echo "    fix-lxd-jwt            JWT_SECRET ÍłįŽ≥łÍįížĚł žĄúŽ≤Ą žěźŽŹô ÍįĪžč† + backend-api žě¨žčúžěĎ"
	@echo "    sync-dev-data          prod DB žĹėŪÖźžł† ‚Üí ÍįĀ LXD Ž°úžĽ¨ dev DB ŽŹôÍłįŪôĒ"
	@echo ""
	@echo "  dev-final žõĆŪĀ¨ŪĒĆŽ°úžöį:"
	@echo "    dev-final-branches     release/feb20-stable + dev/* Ž®łžßÄ ‚Üí dev-final/* ŽłĆŽěúžĻė žÉĚžĄĪ & push"
	@echo "    dev-final-checkout     ÍįĀ LXD žĄúŽ≤ĄžóźžĄú dev-final/* ŽłĆŽěúžĻė checkout"
	@echo "    dev-final-rebuild      ÍįĀ LXD žĄúŽ≤Ą Docker žě¨ŽĻĆŽďú + up -d"
	@echo "    dev-final-setup        žúĄ 3Žč®Í≥Ą žąúžį® žč§ŪĖČ (ž†Ąž≤ī žÖčžóÖ)"
	@echo ""
	@echo "  Ž≥Äžąė:"
	@echo "    REGISTRY=$(REGISTRY)  TAG=$(TAG)"
	@echo ""

# --- Docker Hub Push ---
push:
	@echo "Docker Hub($(REGISTRY)) push..."
	docker push $(REGISTRY)/adelie-frontend:$(TAG)
	docker push $(REGISTRY)/adelie-backend-api:$(TAG)
	docker push $(REGISTRY)/adelie-ai-pipeline:$(TAG)

push-local:
	@for svc in frontend backend-api ai-pipeline; do \
		docker tag $(REGISTRY)/adelie-$$svc:$(TAG) 10.10.10.10:5000/adelie-$$svc:$(TAG); \
		docker push 10.10.10.10:5000/adelie-$$svc:$(TAG); \
	done

# --- Deploy-test (10.10.10.20) ---
deploy-test:
	$(MAKE) -C $(ROOT) build
	$(MAKE) push
	ssh deploy-test 'cd ~/adelie-investment && git pull origin develop && \
		docker compose -f docker-compose.prod.yml pull && \
		docker compose -f docker-compose.prod.yml up -d --remove-orphans && \
		docker exec adelie-frontend nginx -s reload 2>/dev/null || true'

deploy-test-service:
	$(MAKE) -C $(ROOT) build-$(SVC)
	docker push $(REGISTRY)/adelie-$(SVC):$(TAG)
	ssh deploy-test 'cd ~/adelie-investment && git pull origin develop && \
		docker compose -f docker-compose.prod.yml pull $(SVC) && \
		docker compose -f docker-compose.prod.yml up -d $(SVC) && \
		docker exec adelie-frontend nginx -s reload 2>/dev/null || true'

## feb20-stable žĚīŽĮłžßÄŽ°ú deploy-test ŽĻ†Ž•ł Ž°§ŽįĪ
rollback-stable:
	@echo "=== Ž°§ŽįĪ: feb20-stable ‚Üí deploy-test ==="
	ssh deploy-test ' \
	  cd ~/adelie-investment && \
	  git fetch origin && \
	  git checkout release/feb20-stable && \
	  docker pull dorae222/adelie-frontend:feb20-stable && \
	  docker pull dorae222/adelie-backend-api:feb20-stable && \
	  TAG=feb20-stable docker compose -f docker-compose.prod.yml up -d --no-deps frontend backend-api && \
	  docker exec adelie-frontend nginx -s reload 2>/dev/null || true && \
	  echo "‚úÖ Ž°§ŽįĪ žôĄŽ£Ć:" && docker ps --format "{{.Names}}: {{.Image}}" | grep -E "frontend|backend-api" \
	'
	@echo "=== rollback-stable žôĄŽ£Ć ==="

# --- ŽłĆŽěúžĻė žčĪŪĀ¨ (ŪėĄžě¨ git Í≥Ąž†ē žā¨žö© ‚ÄĒ git config Íįēž†ú Ž≥ÄÍ≤Ĺ žóÜžĚĆ) ---
sync-dev-branches:
	@echo "develop ‚Üí dev/* ŽłĆŽěúžĻė žčĪŪĀ¨..."
	@cd $(ROOT) && CURRENT=$$(git branch --show-current); \
	for BRANCH in dev/frontend dev/backend dev/chatbot dev/pipeline dev/infra; do \
		echo "  -> $$BRANCH"; \
		git checkout $$BRANCH 2>/dev/null || { echo "  ŽłĆŽěúžĻė žóÜžĚĆ, ÍĪīŽĄąŽúÄ: $$BRANCH"; continue; }; \
		git merge develop --no-edit 2>/dev/null || true; \
		git push origin $$BRANCH; \
	done; \
	git checkout $$CURRENT
	@echo "žôĄŽ£Ć: Ž™®Žď† dev/* ŽłĆŽěúžĻė žčĪŪĀ¨"

# --- LXD žĄúŽ≤Ą žĹĒŽďú žčĪŪĀ¨ (lxc Ž™ÖŽ†Ļ ‚ÄĒ Ūėłžä§ŪäłžóźžĄúŽßĆ ŽŹôžěĎ) ---
# git pull ŪõĄ frontend dev žĚīŽĮłžßÄ ŽĻĆŽďú ŽįŹ up -d ŪŹ¨Ūē®
sync-lxd:
	@echo "LXD žĄúŽ≤Ą žĹĒŽďú žčĪŪĀ¨ (git pull ‚Üí frontend build ‚Üí up -d)..."
	@lxc exec dev-yj99son  -- bash -c "cd /home/ubuntu/adelie-investment && git pull origin dev/frontend && \
		docker compose -f docker-compose.dev.yml build frontend 2>&1 | tail -3 && \
		docker compose -f docker-compose.dev.yml up -d frontend" && echo "  ‚úÖ dev-yj99son" || echo "  ‚ĚĆ dev-yj99son"
	@lxc exec dev-j2hoon10 -- bash -c "cd /home/ubuntu/adelie-investment && git pull origin dev/chatbot && \
		docker compose -f docker-compose.dev.yml build frontend 2>&1 | tail -3 && \
		docker compose -f docker-compose.dev.yml up -d frontend" && echo "  ‚úÖ dev-j2hoon10" || echo "  ‚ĚĆ dev-j2hoon10"
	@lxc exec dev-ryejinn  -- bash -c "cd /home/ubuntu/adelie-investment && git pull origin dev/pipeline && \
		docker compose -f docker-compose.dev.yml build frontend 2>&1 | tail -3 && \
		docker compose -f docker-compose.dev.yml up -d frontend" && echo "  ‚úÖ dev-ryejinn" || echo "  ‚ĚĆ dev-ryejinn"
	@lxc exec dev-jjjh02   -- bash -c "cd /home/ubuntu/adelie-investment && git pull origin dev/backend && \
		docker compose -f docker-compose.dev.yml build frontend 2>&1 | tail -3 && \
		docker compose -f docker-compose.dev.yml up -d frontend" && echo "  ‚úÖ dev-jjjh02" || echo "  ‚ĚĆ dev-jjjh02"
	@lxc exec dev-hj       -- bash -c "cd /home/ubuntu/adelie-investment && git pull origin dev/infra && \
		docker compose -f docker-compose.dev.yml build frontend 2>&1 | tail -3 && \
		docker compose -f docker-compose.dev.yml up -d frontend" && echo "  ‚úÖ dev-hj" || echo "  ‚ĚĆ dev-hj"
	@echo "žôĄŽ£Ć: Ž™®Žď† LXD žĄúŽ≤Ą žĹĒŽďú žčĪŪĀ¨"

sync-all: sync-dev-branches sync-lxd
	@echo "ž†Ąž≤ī žčĪŪĀ¨ žôĄŽ£Ć (ŽłĆŽěúžĻė + LXD žĄúŽ≤Ą)"

# --- LXD žĄúŽ≤Ą git žĄ§ž†ē ž†źÍ≤Ä ---
check-lxd-git:
	@echo "=== LXD žĄúŽ≤Ą git žĄ§ž†ē ž†źÍ≤Ä ==="
	@for srv in dev-yj99son dev-j2hoon10 dev-jjjh02 dev-ryejinn dev-hj; do \
		echo ""; \
		echo "### $$srv ###"; \
		lxc exec $$srv -- bash -c " \
			cd /home/ubuntu/adelie-investment 2>/dev/null || { echo '  ‚ĚĆ ŪĒĄŽ°úž†ĚŪäł ŽĒĒŽ†ČŪÜ†Ž¶¨ žóÜžĚĆ'; exit 0; }; \
			REMOTE=\$$(git remote get-url origin 2>/dev/null | sed 's|https://[^@]*@|https://***@|g' || echo 'ŽĮłžĄ§ž†ē'); \
			NAME=\$$(git config user.name 2>/dev/null || echo '‚ĚĆ ŽĮłžĄ§ž†ē'); \
			EMAIL=\$$(git config user.email 2>/dev/null || echo '‚ĚĆ ŽĮłžĄ§ž†ē'); \
			SSH_RESULT=\$$(ssh -o StrictHostKeyChecking=no -o ConnectTimeout=5 -T git@github.com 2>&1 | grep -v '^Warning:' | head -1 || true); \
			[ -z \"\$$SSH_RESULT\" ] && SSH_RESULT='‚ĚĆ SSH ŽĮłžĚłž¶Ě (Í≥ĶÍįúŪā§ GitHub ŽĮłŽďĪŽ°Ě)'; \
			echo \"  remote : \$$REMOTE\"; \
			echo \"  user   : \$$NAME <\$$EMAIL>\"; \
			echo \"  ssh    : \$$SSH_RESULT\"; \
		" 2>/dev/null || echo "  ‚ĚĆ LXC žóįÍ≤į žč§ŪĆ®"; \
	done
	@echo ""
	@echo "=== ž†źÍ≤Ä žôĄŽ£Ć ==="

# --- prod DB žĹėŪÖźžł† ‚Üí ÍįĀ LXD Ž°úžĽ¨ dev DB ŽŹôÍłįŪôĒ ---
# HOST(dev-hj)žóźžĄú žč§ŪĖČ: deploy-test prod Žć§ŪĒĄ ‚Üí ÍįĀ LXD žĄúŽ≤Ą Ž°úžĽ¨ postgresžóź ž†Āžö©
sync-dev-data:
	@echo "=== deploy-test ‚Üí ÍįĀ LXD Ž°úžĽ¨ dev DB žĹėŪÖźžł† ŽŹôÍłįŪôĒ ==="
	@bash $(ROOT)/database/scripts/sync_dev_data.sh
	@echo "=== ŽŹôÍłįŪôĒ žôĄŽ£Ć ==="

# --- LXD 5ŽĆÄ žĄúŽ≤Ą Ūó¨žä§ž≤īŪĀ¨ (git ŽłĆŽěúžĻė + Docker žĽ®ŪÖĆžĚīŽĄą žÉĀŪÉú) ---
health-lxd:
	@echo "=== LXD žĄúŽ≤Ą Ūó¨žä§ž≤īŪĀ¨ ==="
	@for srv in dev-yj99son dev-j2hoon10 dev-jjjh02 dev-ryejinn dev-hj; do \
		echo ""; \
		echo "### $$srv ###"; \
		lxc exec $$srv -- bash -c " \
			cd /home/ubuntu/adelie-investment 2>/dev/null || { echo '  ‚ĚĆ ŪĒĄŽ°úž†ĚŪäł ŽĒĒŽ†ČŪÜ†Ž¶¨ žóÜžĚĆ'; exit 0; }; \
			BRANCH=\$$(git branch --show-current 2>/dev/null || echo '‚Ěď ŽĮłŪôēžĚł'); \
			AHEAD=\$$(git rev-list @{u}..HEAD 2>/dev/null | wc -l || echo '?'); \
			BEHIND=\$$(git rev-list HEAD..@{u} 2>/dev/null | wc -l || echo '?'); \
			echo \"  ŽłĆŽěúžĻė  : \$$BRANCH (‚ÜĎ\$$AHEAD ‚Üď\$$BEHIND)\"; \
			echo '  žĽ®ŪÖĆžĚīŽĄą:'; \
			docker compose -f docker-compose.dev.yml ps --format 'table {{.Name}}\t{{.Status}}' 2>/dev/null | tail -n +2 | \
				awk '{printf \"    %-35s %s\n\", \$$1, \$$2}'; \
		" 2>/dev/null || echo "  ‚ĚĆ LXC žóįÍ≤į žč§ŪĆ®"; \
	done
	@echo ""
	@echo "=== Ūó¨žä§ž≤īŪĀ¨ žôĄŽ£Ć ==="

# --- JWT_SECRET ÍłįŽ≥łÍįí žĄúŽ≤Ą žěźŽŹô žąėž†ē ---
# .envžĚė JWT_SECRETžĚī ÍłįŽ≥łÍįížĚīŽ©ī žÉą ŽěúŽć§ÍįížúľŽ°ú ÍĶźž≤ī ŪõĄ backend-api žě¨žčúžěĎ
fix-lxd-jwt:
	@echo "=== JWT_SECRET ÍłįŽ≥łÍįí žĄúŽ≤Ą žąėž†ē ==="
	@DEFAULT_JWT="narrative-invest-jwt-secret-change-in-production"; \
	for srv in dev-yj99son dev-j2hoon10 dev-jjjh02 dev-ryejinn dev-hj; do \
		echo ""; \
		echo "### $$srv ###"; \
		lxc exec $$srv -- bash -c " \
			ENV_FILE=\$$(ls /home/ubuntu/adelie-investment/.env 2>/dev/null | head -1); \
			[ -z \"\$$ENV_FILE\" ] && { echo '  ‚ĚĆ .env ŪĆĆžĚľ žóÜžĚĆ'; exit 0; }; \
			DIR=\$$(dirname \$$ENV_FILE); \
			CURRENT_JWT=\$$(grep '^JWT_SECRET=' \$$ENV_FILE | cut -d= -f2-); \
			if [ \"\$$CURRENT_JWT\" = 'narrative-invest-jwt-secret-change-in-production' ]; then \
				NEW_JWT=\$$(openssl rand -hex 32); \
				sed -i \"s|JWT_SECRET=.*|JWT_SECRET=\$$NEW_JWT|\" \$$ENV_FILE; \
				echo '  ūüĒß JWT_SECRET ÍįĪžč† žôĄŽ£Ć'; \
				cd \$$DIR && docker compose -f docker-compose.dev.yml restart backend-api 2>&1 | tail -2; \
				sleep 8; \
				STATUS=\$$(docker compose -f docker-compose.dev.yml ps backend-api --format '{{.Status}}' 2>/dev/null); \
				echo \"  žÉĀŪÉú: \$$STATUS\"; \
			else \
				echo '  ‚úÖ JWT_SECRET ž†ēžÉĀ (ÍłįŽ≥łÍįí žēĄŽčė)'; \
			fi; \
		" 2>/dev/null || echo "  ‚ĚĆ LXC žóįÍ≤į žč§ŪĆ®"; \
	done
	@echo ""
	@echo "=== JWT žąėž†ē žôĄŽ£Ć ==="

# --- dev-final/* ŽłĆŽěúžĻė žõĆŪĀ¨ŪĒĆŽ°úžöį ---

# Step 1: dev-final/* ŽłĆŽěúžĻė žÉĚžĄĪ (release/feb20-stable + dev/* Ž®łžßÄ)
dev-final-branches:
	@echo "=== dev-final/* ŽłĆŽěúžĻė žÉĚžĄĪ (feb20-stable + dev/* Ž®łžßÄ) ==="
	@cd $(ROOT) && CURRENT=$$(git branch --show-current); \
	git fetch origin; \
	for entry in "frontend:dev/frontend" "chatbot:dev/chatbot" "backend:dev/backend" "pipeline:dev/pipeline" "infra:dev/infra"; do \
		part=$${entry%%:*}; src=$${entry##*:}; \
		echo ""; \
		echo "  ‚Üí dev-final/$$part (‚Üź origin/$$src)"; \
		git checkout release/feb20-stable 2>/dev/null || { echo "  ‚ĚĆ release/feb20-stable žóÜžĚĆ"; continue; }; \
		git checkout -b dev-final/$$part 2>/dev/null || git checkout dev-final/$$part; \
		if git merge --no-edit origin/$$src 2>/dev/null; then \
			git push origin dev-final/$$part \
				&& echo "  ‚úÖ dev-final/$$part push žôĄŽ£Ć" \
				|| echo "  ‚ö†ÔłŹ  push žč§ŪĆ® ‚ÄĒ Í∂ĆŪēú ŽėźŽäĒ remote ŪôēžĚł"; \
		else \
			echo "  ‚ö†ÔłŹ  dev-final/$$part: ž∂©ŽŹĆ ŽįúžÉĚ ‚ÄĒ žąėŽŹô ŪēīÍ≤į ŪõĄ git push origin dev-final/$$part žč§ŪĖČ"; \
			git merge --abort 2>/dev/null || true; \
		fi; \
	done; \
	git checkout $$CURRENT
	@echo ""
	@echo "=== ŽłĆŽěúžĻė žÉĚžĄĪ žôĄŽ£Ć ==="

# Step 2: ÍįĀ LXD žĄúŽ≤ĄžóźžĄú dev-final/* checkout
dev-final-checkout:
	@echo "=== ÍįĀ LXD žĄúŽ≤Ą dev-final/* checkout ==="
	@lxc exec dev-yj99son  -- bash -c "cd /home/ubuntu/adelie-investment && git fetch origin && git stash 2>/dev/null || true && git checkout dev-final/frontend  && echo '  ‚úÖ dev-yj99son: dev-final/frontend'"  2>/dev/null && true || echo "  ‚ĚĆ dev-yj99son"
	@lxc exec dev-j2hoon10 -- bash -c "cd /home/ubuntu/adelie-investment && git fetch origin && git stash 2>/dev/null || true && git checkout dev-final/chatbot   && echo '  ‚úÖ dev-j2hoon10: dev-final/chatbot'"  2>/dev/null && true || echo "  ‚ĚĆ dev-j2hoon10"
	@lxc exec dev-jjjh02   -- bash -c "cd /home/ubuntu/adelie-investment && git fetch origin && git stash 2>/dev/null || true && git checkout dev-final/backend   && echo '  ‚úÖ dev-jjjh02: dev-final/backend'"   2>/dev/null && true || echo "  ‚ĚĆ dev-jjjh02"
	@lxc exec dev-ryejinn  -- bash -c "cd /home/ubuntu/adelie-investment && git fetch origin && git stash 2>/dev/null || true && git checkout dev-final/pipeline  && echo '  ‚úÖ dev-ryejinn: dev-final/pipeline'"  2>/dev/null && true || echo "  ‚ĚĆ dev-ryejinn"
	@lxc exec dev-hj       -- bash -c "cd /home/ubuntu/adelie-investment && git fetch origin && git stash 2>/dev/null || true && git checkout dev-final/infra     && echo '  ‚úÖ dev-hj: dev-final/infra'"        2>/dev/null && true || echo "  ‚ĚĆ dev-hj"
	@echo "=== checkout žôĄŽ£Ć (ŽĮłžĽ§Žįč Ž≥ÄÍ≤Ĺžā¨Ūē≠žĚÄ ÍįĀ žĄúŽ≤Ą git stash list ŪôēžĚł) ==="

# Step 3: ÍįĀ LXD žĄúŽ≤Ą Docker žě¨ŽĻĆŽďú + up -d (frontend + backend-apiŽßĆ, ai-pipeline ž†úžôł)
dev-final-rebuild:
	@echo "=== ÍįĀ LXD žĄúŽ≤Ą Docker žě¨ŽĻĆŽďú (frontend + backend-api) ==="
	@for srv in dev-yj99son dev-j2hoon10 dev-jjjh02 dev-ryejinn dev-hj; do \
		echo ""; \
		echo "  ūüď¶ $$srv ŽĻĆŽďú ž§Ď..."; \
		lxc exec $$srv -- bash -c " \
			cd /home/ubuntu/adelie-investment && \
			docker compose -f docker-compose.dev.yml build frontend backend-api 2>&1 | tail -3 && \
			docker compose -f docker-compose.dev.yml up -d --remove-orphans" \
			&& echo "  ‚úÖ $$srv žě¨žčúžěĎ žôĄŽ£Ć" || echo "  ‚ĚĆ $$srv ŽĻĆŽďú žč§ŪĆ®"; \
	done
	@echo ""
	@echo "=== žě¨ŽĻĆŽďú žôĄŽ£Ć (ai-pipelinežĚÄ ŪēĄžöĒ žčú žąėŽŹô: docker compose build ai-pipeline) ==="

# dev-final ž†Ąž≤ī žÖčžóÖ (ŽłĆŽěúžĻė žÉĚžĄĪ ‚Üí checkout ‚Üí žě¨ŽĻĆŽďú)
dev-final-setup: dev-final-branches dev-final-checkout dev-final-rebuild
	@echo ""
	@echo "‚úÖ dev-final ž†Ąž≤ī žÖčžóÖ žôĄŽ£Ć"
	@echo "   Žč§žĚĆ Žč®Í≥Ą: ŪĆĆžĚīŪĒĄŽĚľžĚł žąėžßĎ žôĄŽ£Ć ŪõĄ ‚Üí make -f lxd/Makefile sync-dev-data"

